<p-table [value]="donors" [paginator]="true" [rows]="10">

  <ng-template pTemplate="header">
    <tr>
      <th>שם</th>
      <th>טלפון</th>
      <th>מתנות</th>
    </tr>
  </ng-template>

  <ng-template pTemplate="body" let-donor>
    <tr>
      <td>{{ donor.firstName }} {{ donor.lastName }}</td>
      <td>{{ donor.phone }}</td>
      <td>
        <a [routerLink]="['/donors', donor.id]">
          הצג מתנות
        </a>
      </td>
    </tr>
  </ng-template>

</p-table>
